<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Personal Expense Tracker</title>
  <style>
    * { box-sizing: border-box; }
    body { font-family: system-ui, sans-serif; max-width: 700px; margin: 2rem auto; padding: 0 1rem; line-height: 1.5; }
    h1 { margin-bottom: 1.5rem; }
    .form-row { display: flex; gap: 0.5rem; flex-wrap: wrap; margin-bottom: 0.75rem; align-items: flex-end; }
    .form-row label { font-weight: 600; min-width: 80px; }
    .form-row input, .form-row select { flex: 1; min-width: 140px; padding: 0.5rem; border: 1px solid #ccc; border-radius: 4px; font-size: 1rem; }
    .form-row input[type="number"] { width: 100px; }
    .form-row input[type="text"] { flex: 2; min-width: 200px; }
    #add-expense { padding: 0.6rem 1.2rem; font-size: 1rem; background: #2563eb; color: white; border: none; border-radius: 4px; cursor: pointer; }
    #add-expense:hover { background: #1d4ed8; }
    #form-error { color: #dc2626; min-height: 1.25rem; margin-bottom: 1rem; }
    table { width: 100%; border-collapse: collapse; margin-top: 1rem; }
    th, td { padding: 0.6rem; text-align: left; border-bottom: 1px solid #e5e7eb; }
    th { background: #f9fafb; font-weight: 600; }
    .expense td { vertical-align: middle; }
    .exp-del { background: #ef4444; color: white; border: none; padding: 0.3rem 0.6rem; border-radius: 3px; cursor: pointer; font-size: 0.85rem; }
    .exp-del:hover { background: #dc2626; }
    .summary { margin-top: 1.5rem; padding: 1rem; background: #f9fafb; border-radius: 6px; }
    .summary-row { display: flex; justify-content: space-between; margin: 0.4rem 0; }
    .summary-row.total { font-weight: 700; font-size: 1.1rem; border-top: 1px solid #d1d5db; padding-top: 0.6rem; margin-top: 0.6rem; }
    .filters { display: flex; gap: 1rem; flex-wrap: wrap; margin: 1rem 0; padding: 1rem; background: #f9fafb; border-radius: 6px; }
    .filters label { display: flex; flex-direction: column; gap: 0.25rem; font-size: 0.9rem; }
    .filters select, .filters input { padding: 0.4rem; border: 1px solid #ccc; border-radius: 4px; font-size: 0.9rem; }
    .hidden { display: none !important; }
  </style>
</head>
<body>
  <h1>Personal Expense Tracker</h1>

  <form id="expense-form">
    <div class="form-row">
      <label for="amount">Amount</label>
      <input type="number" id="amount" step="0.01" min="0.01" placeholder="0.00" required>
    </div>
    <div class="form-row">
      <label for="category">Category</label>
      <select id="category" required>
        <option value="groceries">Groceries</option>
        <option value="transport">Transport</option>
        <option value="bills">Bills</option>
        <option value="fun">Fun</option>
      </select>
    </div>
    <div class="form-row">
      <label for="date">Date</label>
      <input type="date" id="date" required>
    </div>
    <div class="form-row">
      <label for="note">Note (optional)</label>
      <input type="text" id="note" placeholder="Description...">
    </div>
    <button type="submit" id="add-expense">Add Expense</button>
    <div id="form-error"></div>
  </form>

  <div class="filters">
    <label>Category
      <select id="filter-category">
        <option value="all">All</option>
        <option value="groceries">Groceries</option>
        <option value="transport">Transport</option>
        <option value="bills">Bills</option>
        <option value="fun">Fun</option>
      </select>
    </label>
    <label>From
      <input type="date" id="filter-from">
    </label>
    <label>To
      <input type="date" id="filter-to">
    </label>
  </div>

  <table>
    <thead>
      <tr>
        <th>Amount</th>
        <th>Category</th>
        <th>Date</th>
        <th>Note</th>
        <th></th>
      </tr>
    </thead>
    <tbody id="expense-list"></tbody>
  </table>

  <div class="summary">
    <div class="summary-row"><span>Groceries</span><span class="cat-total" data-cat="groceries">0.00</span></div>
    <div class="summary-row"><span>Transport</span><span class="cat-total" data-cat="transport">0.00</span></div>
    <div class="summary-row"><span>Bills</span><span class="cat-total" data-cat="bills">0.00</span></div>
    <div class="summary-row"><span>Fun</span><span class="cat-total" data-cat="fun">0.00</span></div>
    <div class="summary-row total"><span>Total</span><span id="total">0.00</span></div>
  </div>

  <script>
    const STORAGE_KEY = 'expenses_v1';
    const CATEGORIES = ['groceries', 'transport', 'bills', 'fun'];

    let expenses = [];

    function loadExpenses() {
      try {
        const stored = localStorage.getItem(STORAGE_KEY);
        if (stored) {
          expenses = JSON.parse(stored);
          expenses.sort((a, b) => new Date(b.date) - new Date(a.date));
        }
      } catch (e) {
        expenses = [];
      }
    }

    function saveExpenses() {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
    }

    function formatCurrency(val) {
      return val.toFixed(2);
    }

    function render() {
      const catFilter = document.getElementById('filter-category').value;
      const fromFilter = document.getElementById('filter-from').value;
      const toFilter = document.getElementById('filter-to').value;

      const list = document.getElementById('expense-list');
      list.innerHTML = '';

      const catTotals = { groceries: 0, transport: 0, bills: 0, fun: 0 };
      let total = 0;

      expenses.forEach((expense, idx) => {
        const matchesCategory = catFilter === 'all' || expense.category === catFilter;
        const matchesFrom = !fromFilter || expense.date >= fromFilter;
        const matchesTo = !toFilter || expense.date <= toFilter;
        const visible = matchesCategory && matchesFrom && matchesTo;

        if (visible) {
          catTotals[expense.category] += expense.amount;
          total += expense.amount;
        }

        const row = document.createElement('tr');
        row.className = 'expense';
        if (!visible) row.classList.add('hidden');
        row.innerHTML = `
          <td>${formatCurrency(expense.amount)}</td>
          <td>${expense.category}</td>
          <td>${expense.date}</td>
          <td>${expense.note || ''}</td>
          <td><button class="exp-del" data-index="${idx}">Delete</button></td>
        `;
        list.appendChild(row);
      });

      document.getElementById('total').textContent = formatCurrency(total);
      CATEGORIES.forEach(cat => {
        const el = document.querySelector(`.cat-total[data-cat="${cat}"]`);
        if (el) el.textContent = formatCurrency(catTotals[cat]);
      });
    }

    function addExpense(e) {
      e.preventDefault();
      const amountEl = document.getElementById('amount');
      const categoryEl = document.getElementById('category');
      const dateEl = document.getElementById('date');
      const noteEl = document.getElementById('note');
      const errorEl = document.getElementById('form-error');

      const amount = parseFloat(amountEl.value);
      const category = categoryEl.value;
      const date = dateEl.value;
      const note = noteEl.value.trim();

      errorEl.textContent = '';

      if (!date) {
        errorEl.textContent = 'Date is required.';
        return;
      }
      if (isNaN(amount) || amount <= 0) {
        errorEl.textContent = 'Amount must be a positive number.';
        return;
      }

      const expense = { amount, category, date, note };
      expenses.unshift(expense);
      saveExpenses();

      amountEl.value = '';
      noteEl.value = '';
      dateEl.value = '';
      render();
    }

    function deleteExpense(e) {
      if (!e.target.classList.contains('exp-del')) return;
      const idx = parseInt(e.target.dataset.index, 10);
      if (!isNaN(idx) && idx >= 0 && idx < expenses.length) {
        expenses.splice(idx, 1);
        saveExpenses();
        render();
      }
    }

    function init() {
      loadExpenses();
      document.getElementById('expense-form').addEventListener('submit', addExpense);
      document.getElementById('expense-list').addEventListener('click', deleteExpense);
      document.getElementById('filter-category').addEventListener('change', render);
      document.getElementById('filter-from').addEventListener('change', render);
      document.getElementById('filter-to').addEventListener('change', render);
      render();
    }

    init();
  </script>
</body>
</html>
